from flask import Flask, redirect, request, session, url_for, render_template_string, abort
from urllib.parse import urlencode
import os

app = Flask(__name__)
app.secret_key = os.environ.get("FLASK_SECRET_KEY", "dev-secret-key")

OIDC_ISSUER = os.environ.get("OIDC_ISSUER", "").rstrip("/")
OIDC_AUTHORIZATION_ENDPOINT = os.environ.get("OIDC_AUTHORIZATION_ENDPOINT", "")
OIDC_CLIENT_ID = os.environ.get("OIDC_CLIENT_ID", "")
OIDC_REDIRECT_URI = os.environ.get("OIDC_REDIRECT_URI", "")
OIDC_SCOPE = "openid"
OIDC_RESPONSE_TYPE = "id_token"

LOGIN_TEMPLATE = """
<!doctype html>
<html>
  <body>
    <h1>Admin Dashboard</h1>
    {% if user %}
      <p>Logged in as: {{ user }}</p>
      <p><a href="{{ url_for('logout') }}">Logout</a></p>
    {% else %}
      <p>You are not logged in.</p>
      <p><a href="{{ url_for('login') }}">Login with SSO</a></p>
    {% endif %}
  </body>
</html>
"""

def build_authorization_url():
    if not OIDC_AUTHORIZATION_ENDPOINT:
        abort(500, "Missing OIDC_AUTHORIZATION_ENDPOINT")
    if not OIDC_CLIENT_ID:
        abort(500, "Missing OIDC_CLIENT_ID")
    if not OIDC_REDIRECT_URI:
        abort(500, "Missing OIDC_REDIRECT_URI")

    params = {
        "client_id": OIDC_CLIENT_ID,
        "redirect_uri": OIDC_REDIRECT_URI,
        "scope": OIDC_SCOPE,
        "response_type": OIDC_RESPONSE_TYPE,
    }
    return f"{OIDC_AUTHORIZATION_ENDPOINT}?{urlencode(params)}"

@app.route("/")
def index():
    user = session.get("user")
    return render_template_string(LOGIN_TEMPLATE, user=user)

@app.route("/login")
def login():
    return redirect(build_authorization_url())

@app.route("/callback")
def callback():
    error = request.args.get("error")
    if error:
        desc = request.args.get("error_description", "")
        return f"Authentication failed: {error} {desc}", 400

    id_token = request.args.get("id_token")
    if not id_token:
        return "Missing id_token in callback", 400

    session["user"] = "authenticated"
    session["id_token"] = id_token
    return redirect(url_for("index"))

@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("index"))

